//! Solution for https://leetcode.com/problems/jump-game-vii
//! 1871. Jump Game VII

impl Solution {
    pub fn can_reach(s: String, min_jump: i32, max_jump: i32) -> bool {
        let mut bytes = s.into_bytes();
        let mut queue = std::collections::VecDeque::new();
        let mut further = 0;
        queue.push_front(0);
        bytes[0] = b'1';

        while let Some(i) = queue.pop_back() {
            if i + 1 == bytes.len() {
                return true;
            }
            for j in (i + min_jump as usize).max(further + 1)
                ..((i + 1 + max_jump as usize).min(bytes.len()))
            {
                if bytes[j] == b'0' {
                    bytes[j] = b'1';
                    further = j.max(further);
                    queue.push_front(j);
                }
            }
        }
        false
    }
}

