#[cfg(test)]
mod tests {
    use super::*;

    use rstest::rstest;

    #[rstest]
    #[case("011010", 2, 3, true)]
    #[case("01101110", 2, 3, false)]
    #[case("011111000111000001011111010", 6, 8, true)]
    #[case(
        "",
        1,
        9999,
        false
    )]
    fn case(
        #[case] s: String,
        #[case] min_jump: i32,
        #[case] max_jump: i32,
        #[case] expected: bool,
    ) {
        let actual = Solution::can_reach(s, min_jump, max_jump);
        assert_eq!(actual, expected);
    }
}
